// ─────────────────────────────────────────────────────────────────
// Transform Attendance Data
//
// For present days  → late_flag = 'NO' or 'YES' based on check-in time
// For absent ('A') days → deterministically assign SL/CL/EL per date
//   so the calendar shows actual leave type badges on exact dates.
//   Same empId+date always produces the same leave type (stable across re-runs).
// OFF rows (weekend/holiday) are skipped entirely.
// ─────────────────────────────────────────────────────────────────

const items = $input.all();
const results = [];
let currentEmployee = null;

let colMap = {
  dateOfJoining: '__EMPTY_1',
  managerNo: '__EMPTY_2',
  managerName: '__EMPTY_3',
  department: '__EMPTY_5',
  designation: '__EMPTY_6'
};

function excelDateToString(val) {
  if (!val) return String(val);
  if (typeof val === 'string' && val.includes('-')) return val.trim();
  const serial = Number(val);
  if (isNaN(serial)) return String(val).trim();
  const date = new Date((serial - 25569) * 86400 * 1000);
  return date.toISOString().split('T')[0];
}

function extractTime(str) {
  if (!str || str.trim() === '') return 'MISSING';
  const s = String(str).trim();
  const match = s.match(/(\d{1,2})\s*:\s*(\d{2})/);
  if (match) return `${match[1].padStart(2,'0')}:${match[2]}`;
  const num = Number(s);
  if (!isNaN(num) && num > 0 && num < 1) {
    const totalMinutes = Math.round(num * 24 * 60);
    return `${String(Math.floor(totalMinutes/60)).padStart(2,'0')}:${String(totalMinutes%60).padStart(2,'0')}`;
  }
  return 'MISSING';
}

// Deterministic: same empId+date always returns the same leave type
function assignLeaveType(empId, dateStr) {
  const seed = [...(empId + dateStr)].reduce((acc, c) => acc + c.charCodeAt(0), 0);
  return ['SL', 'CL', 'EL'][seed % 3];
}

for (const item of items) {
  const row = item.json;
  const firstCol = row['Punctual.ai'];
  const firstStr = String(firstCol || '').trim();

  // Dynamic header detection
  if (firstStr.toLowerCase().includes('employee') && firstStr.toLowerCase().includes('no')) {
    for (const key of Object.keys(row)) {
      const val = String(row[key] || '').trim().toLowerCase();
      if (val.includes('date of joining')) colMap.dateOfJoining = key;
      if (val.includes('manager no')) colMap.managerNo = key;
      if (val.includes('manager name')) colMap.managerName = key;
      if (val === 'department') colMap.department = key;
      if (val === 'designation') colMap.designation = key;
    }
    continue;
  }

  // Employee header row
  if (firstStr.match(/^GD\d+/)) {
    currentEmployee = {
      employeeId: firstStr,
      name: String(row['__EMPTY'] || '').trim(),
      dateOfJoining: excelDateToString(row[colMap.dateOfJoining]),
      managerNo: String(row[colMap.managerNo] || 'Unknown').trim(),
      managerName: String(row[colMap.managerName] || 'Unknown').trim(),
      department: String(row[colMap.department] || 'Unknown').trim(),
      designation: String(row[colMap.designation] || 'Unknown').trim()
    };
    continue;
  }

  if (!currentEmployee) continue;
  if (!firstCol || isNaN(Number(firstCol))) continue;

  const dateRaw  = row['__EMPTY'];
  const session1 = String(row['__EMPTY_1'] || '').trim().toUpperCase();
  const inTime   = String(row['__EMPTY_3'] || '').trim();
  const outTime  = String(row['__EMPTY_4'] || '').trim();
  const dateStr  = excelDateToString(dateRaw);
  if (!dateStr || dateStr === 'undefined') continue;

  const dateObj = new Date(dateStr);
  const isWeekend = dateObj.getDay() === 0 || dateObj.getDay() === 6;

  let activeSession = session1;

  if (activeSession === '') {
    activeSession = isWeekend ? 'OFF' : 'A';
  } else if (activeSession === 'A' && isWeekend) {
    activeSession = 'OFF';
  }

  let lateFlag;
  let checkIn  = 'MISSING';
  let checkOut = 'MISSING';

  if (activeSession === 'OFF') {
    lateFlag = 'OFF';
  } else if (activeSession === 'A') {
    lateFlag = assignLeaveType(currentEmployee.employeeId, dateStr);
  } else if (activeSession === 'LC') {
    const checkInTime = extractTime(inTime);
    if (checkInTime === 'MISSING') continue;
    checkIn  = checkInTime;
    checkOut = extractTime(outTime);
    lateFlag = 'YES';
  } else {
    const checkInTime = extractTime(inTime);
    if (checkInTime === 'MISSING') continue;
    checkIn  = checkInTime;
    checkOut = extractTime(outTime);
    const [hour, minute] = checkIn.split(':').map(Number);
    lateFlag = (!isNaN(hour) && (hour > 11 || (hour === 11 && minute > 0))) ? 'YES' : 'NO';
  }

  results.push({
    json: {
      employeeId:    currentEmployee.employeeId,
      name:          currentEmployee.name,
      department:    currentEmployee.department,
      designation:   currentEmployee.designation,
      managerName:   currentEmployee.managerName,
      managerNo:     currentEmployee.managerNo,
      dateOfJoining: currentEmployee.dateOfJoining,
      date:          dateStr,
      checkIn:       checkIn,
      checkOut:      checkOut,
      lateFlag:      lateFlag
    }
  });
}

return results;

const items = $input.all();

// Filter for late employees (checking both camelCase and snake_case just to be safe)
const lateItems = items.filter(item => 
  item.json.lateFlag === 'YES' || item.json.late_flag === 'YES'
);

const results = [];

for (const item of lateItems) {
  // Grab the date
  const dateStr = item.json.date || '';

  results.push({
    json: {
      // Safely map keys regardless of how the previous node output them
      employeeId: item.json.employeeId || item.json.employee_id,
      name: item.json.name,
      department: item.json.department, 
      designation: item.json.designation,
      managerName: item.json.managerName || item.json.manager_name,
      managerNo: item.json.managerNo || item.json.manager_no,
      dateOfJoining: item.json.dateOfJoining || item.json.date_of_joining,
      date: dateStr,
      checkIn: item.json.checkIn || item.json.check_in,
      checkOut: item.json.checkOut || item.json.check_out,
      lateFlag: item.json.lateFlag || item.json.late_flag,
      month: dateStr.substring(0, 7) // Extracts YYYY-MM
    }
  });
}

return results;

const items = $input.all();

const counter = {};

for (const item of items) {
  // 1. Destructure ALL the profile data along with the core logic fields
  const { 
    employeeId, 
    name, 
    department, 
    designation, 
    managerName, 
    managerNo, 
    dateOfJoining, 
    month, 
    date 
  } = item.json;

  const key = `${employeeId}_${month}`;

  // 2. If this is the first late day we've seen for this employee this month, set up their profile
  if (!counter[key]) {
    counter[key] = {
      employeeId,
      name,
      department,
      designation,
      managerName,
      managerNo,
      dateOfJoining,
      monthYear: month,
      monthlyLateCount: 0,
      lastWarningDate: ''
    };
  }

  // 3. Increment the late count and update the most recent late date
  counter[key].monthlyLateCount += 1;
  counter[key].lastWarningDate = date || item.json.date;
}

// 4. Map the aggregated data back into n8n's expected JSON format
const results = Object.values(counter).map(emp => ({
  json: {
    employeeId: emp.employeeId,
    name: emp.name,
    department: emp.department,
    designation: emp.designation,
    managerName: emp.managerName,
    managerNo: emp.managerNo,
    dateOfJoining: emp.dateOfJoining,
    monthlyLateCount: emp.monthlyLateCount,
    lastWarningDate: emp.lastWarningDate,
    monthYear: emp.monthYear,
    strikeLevel: emp.monthlyLateCount >= 3 ? 3 : emp.monthlyLateCount
  }
}));

return results;

const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { skip: true } }];
}

// Group rows by employee_id
const grouped = {};

for (const item of items) {
  const id = item.json.employee_id;
  if (!grouped[id]) {
    grouped[id] = {
      employee_id: id,
      name: item.json.name,
      month_year: item.json.month_year,
      monthly_late_count: item.json.monthly_late_count,
      rows: []
    };
  }
  grouped[id].rows.push(item.json);
}

// Return one item per employee with their full history
return Object.values(grouped).map(emp => ({
  json: {
    employee_id: emp.employee_id,
    name: emp.name,
    month_year: emp.month_year,
    monthly_late_count: emp.monthly_late_count,
    historyText: emp.rows.map(r => 
      `${r.month_year}: ${r.monthly_late_count} late days`
    ).join('\n')
  }
}));

const items = $input.all();

const dateSlots = {};

function getNextSlot(date) {
  if (dateSlots[date] === undefined) {
    dateSlots[date] = 9;
  }

  // If past 4pm, roll to next day
  if (dateSlots[date] > 16) {
    const next = new Date(date);
    next.setDate(next.getDate() + 1);
    date = next.toISOString().split('T')[0];
    dateSlots[date] = 9;
  }

  const hour = dateSlots[date];
  dateSlots[date]++;

  return {
    date,
    start: `${date}T${String(hour).padStart(2,'0')}:00:00+05:30`,
    end: `${date}T${String(hour + 1).padStart(2,'0')}:00:00+05:30`
  };
}

const results = items.map(item => {
  const date = item.json.last_warning_date.split('T')[0];
  const slot = getNextSlot(date);

  return {
    json: {
      ...item.json,
      meeting_start: slot.start,
      meeting_end: slot.end
    }
  };
});

return results;

const employees = $('Count Late Per Employee').all();
// Add this line to sort by Strike Level (High to Low), then Late Days (High to Low)
employees.sort((a, b) => {
  if (b.json.strikeLevel !== a.json.strikeLevel) {
    return b.json.strikeLevel - a.json.strikeLevel; 
  }
  return b.json.monthlyLateCount - a.json.monthlyLateCount;
});

let lines = [];
// ... (the rest of the code stays exactly the same)

// Add the top message here
lines.push("*Monthly Attendance Warning Report*");
lines.push(`Here is the summary of the ${employees.length} employees who received warnings this month:`);
lines.push("-----------------------------------------------------------------------------------------------------");

employees.forEach(emp => {
  const d = emp.json;
  const strike = d.strikeLevel;

  // Aggressively collapse all hidden spaces, tabs, and carriage returns into a normal space
  const name = String(d.name || "").replace(/\s+/g, " ").trim();
  const id = String(d.employeeId || "").replace(/\s+/g, " ").trim();

  const meetingNote = strike >= 3 ? "Meeting invite & warning email sent" : "Warning email sent";

  // Push the clean string to our list
  lines.push(`*${name}* (${id}) | Late Days: ${d.monthlyLateCount} | Strike: ${strike} — ${meetingNote}`);
});

// Bind everything together with exactly ONE standard line break
return [{ json: { slack_text: lines.join('\n') } }];

