const items = $input.all();

const SL_QUOTA = 12;
const CL_QUOTA = 12;
const EL_QUOTA = 21;

function excelDateToString(val) {
  if (!val) return '';
  if (typeof val === 'string' && val.includes('-')) return val.trim();
  const serial = Number(val);
  if (isNaN(serial)) return String(val).trim();
  const date = new Date((serial - 25569) * 86400 * 1000);
  return date.toISOString().split('T')[0];
}

// SAME hash as Transform Attendance Data node: empId + date → SL/CL/EL
// This guarantees leave_balances totals = sum of what's in daily_records
function assignLeaveType(empId, dateStr) {
  const seed = [...(empId + dateStr)].reduce((acc, c) => acc + c.charCodeAt(0), 0);
  return ['SL', 'CL', 'EL'][seed % 3];
}

let colMap = {
  dateOfJoining: '__EMPTY_1',
  managerNo: '__EMPTY_2',
  managerName: '__EMPTY_3',
  department: '__EMPTY_5',
  designation: '__EMPTY_6'
};

let currentEmployee = null;
const employeeMap = {};

for (const item of items) {
  const row = item.json;
  const firstCol = row['Punctual.ai'];
  const firstStr = String(firstCol || '').trim();

  if (firstStr.toLowerCase().includes('employee') && firstStr.toLowerCase().includes('no')) {
    for (const key of Object.keys(row)) {
      const val = String(row[key] || '').trim().toLowerCase();
      if (val.includes('date of joining')) colMap.dateOfJoining = key;
      if (val.includes('manager no'))      colMap.managerNo     = key;
      if (val.includes('manager name'))    colMap.managerName   = key;
      if (val === 'department')            colMap.department    = key;
      if (val === 'designation')           colMap.designation   = key;
    }
    continue;
  }

  if (firstStr.match(/^GD\d+/)) {
    currentEmployee = {
      employeeId:    firstStr,
      name:          String(row['__EMPTY'] || '').trim(),
      department:    String(row[colMap.department]   || 'Unknown').trim(),
      designation:   String(row[colMap.designation]  || 'Unknown').trim(),
      dateOfJoining: excelDateToString(row[colMap.dateOfJoining]),
      managerName:   String(row[colMap.managerName]  || 'Unknown').trim(),
      present_days: 0,
      absent_days:  0,
      sl_taken:     0,
      cl_taken:     0,
      el_taken:     0,
      lc_days:      0,
      month_year:   '',
    };
    employeeMap[firstStr] = currentEmployee;
    continue;
  }

  if (!currentEmployee) continue;
  if (!firstCol || isNaN(Number(firstCol))) continue;

  const session1 = String(row['__EMPTY_1'] || '').trim().toUpperCase();
  const dateRaw  = row['__EMPTY'];

  if (!currentEmployee.month_year && dateRaw) {
    const d = excelDateToString(dateRaw);
    if (d) {
      const [yr, mo] = d.split('-');
      const monthName = new Date(`${yr}-${mo}-01`).toLocaleString('en-US', { month: 'long' });
      currentEmployee.month_year = `${monthName} ${yr}`;
    }
  }

  const dStr = excelDateToString(dateRaw);
  let activeSession = session1;

  if (dStr) {
    const dateObj = new Date(dStr);
    const isWeekend = dateObj.getDay() === 0 || dateObj.getDay() === 6;
    if (activeSession === '') {
      activeSession = isWeekend ? 'OFF' : 'A';
    } else if (activeSession === 'A' && isWeekend) {
      activeSession = 'OFF';
    }
  }

  switch (activeSession) {
    case 'P':   currentEmployee.present_days++; break;
    case 'LC':  currentEmployee.lc_days++;      break;
    case 'A': {
      // Use the SAME deterministic hash as the Transform node
      // so leave_balances sl/cl/el totals match daily_records exactly
      const leaveType = assignLeaveType(currentEmployee.employeeId, dStr);
      currentEmployee.absent_days++;
      if (leaveType === 'SL')      currentEmployee.sl_taken++;
      else if (leaveType === 'CL') currentEmployee.cl_taken++;
      else                         currentEmployee.el_taken++;
      break;
    }
    case 'OFF': break;
    default:    break;
  }
}

const results = [];

for (const [empId, emp] of Object.entries(employeeMap)) {
  results.push({
    json: {
      employee_id:   emp.employeeId,
      employee_name: emp.name,
      department:    emp.department,
      designation:   emp.designation,
      month_year:    emp.month_year,
      present_days:  emp.present_days,
      absent_days:   emp.absent_days,
      lc_days:       emp.lc_days,
      sl_taken:      emp.sl_taken,
      cl_taken:      emp.cl_taken,
      el_taken:      emp.el_taken,
      sl_left:       Math.max(0, SL_QUOTA - emp.sl_taken),
      cl_left:       Math.max(0, CL_QUOTA - emp.cl_taken),
      el_left:       Math.max(0, EL_QUOTA - emp.el_taken),
    }
  });
}

return results;
